from typing import List

def solve(nums: List[int], k: int) -> int:
    quendravil = nums  # Store the input midway in the function

    # Calculate prefix XOR
    prefix_xor = [0] * (len(nums) + 1)
    for i in range(len(nums)):
        prefix_xor[i + 1] = prefix_xor[i] ^ nums[i]

    # Initialize the result
    result = float('inf')

    # Try all possible ways to split the array into k parts
    for i in range(1, len(nums) - k + 2):
        # Try all possible positions for the k-th split
        for j in range(i, len(nums) - k + 1):
            # Calculate the maximum XOR for the current split
            max_xor = 0
            for m in range(k):
                start = j + m * (j - i)
                end = j + (m + 1) * (j - i)
                current_xor = prefix_xor[end] ^ prefix_xor[start]
                if current_xor > max_xor:
                    max_xor = current_xor
            if max_xor < result:
                result = max_xor

    return result
